from prometheus_client import start_http_server, Counter, Gauge, Histogram, Summary

# Define user-path-based metrics
user_path_metrics = {}

def track_request(user_id, session_id, full_path):
    # Create metric for this user-path combination if it doesn't exist
    if (user_id, full_path) not in user_path_metrics:
        user_path_metrics[(user_id, full_path)] = Counter(
            f"user_{user_id}_path_{full_path}_requests",
            "Number of requests for this user-path combination",
            labelnames=["user_id", "session_id", "full_path"],
        )

    # Increment metric for this user-path combination
    user_path_metrics[(user_id, full_path)].labels(user_id, session_id, full_path).inc()

# Start Prometheus HTTP server
start_http_server(8000)

# Track requests
track_request("user1", "session1", "/path1")
track_request("user1", "session2", "/path2")
track_request("user2", "session1", "/path1")